// Formater la réponse de rechargement
const response = $input.item.json.result || $input.item.json;
const data = response.data || response;

if (response.status !== 'success') {
  return {
    json: {
      success: false,
      message: `❌ Erreur lors du rechargement: ${response.msg || 'Erreur inconnue'}`,
      error: response.msg
    }
  };
}

let formattedText = '✅ **Configuration rechargée avec succès** ✅\n\n';

if (data && typeof data === 'object') {
  const instances = Object.keys(data);
  formattedText += `**Instances rechargées (${instances.length}):**\n\n`;

  instances.forEach(instance => {
    if (data[instance].status === 'success') {
      formattedText += `• ${instance}: ✅ OK\n`;
    } else {
      formattedText += `• ${instance}: ❌ ${data[instance].msg || 'Erreur'}\n`;
    }
  });
}

return {
  json: {
    success: true,
    message: formattedText,
    data: data
  }
};
